const formatMessage = require('format-message');
const BlockType = require('../../extension-support/block-type');
const ArgumentType = require('../../extension-support/argument-type');
const Cast = require('../../util/cast');

// eslint-disable-next-line max-len
const iconURI = `data:image/svg+xml;base64,`;
/**
 * Class for TurboWarp blocks
 * @constructor
 */
class commentExt {
    constructor (runtime) {
        /**
         * The runtime instantiating this block package.
         * @type {Runtime}
         */
        this.runtime = runtime;
    }

    /**
     * @returns {object} metadata for this extension and its blocks.
     */
    getInfo () {
        return {
            id: 'commentExt',
            name: 'Comment Extension',
            color1: '#f5deb3',
            color2: '#deb887',
            color3: '#fffacd',
            blockIconURI: iconURI,
            blocks: [
            {
                opcode: 'commentCommand',
                blockType: BlockType.COMMAND,
                text: '// [COMMENT]',
                arguments: {
                COMMENT: {
                    type: ArgumentType.STRING,
                    defaultValue: 'Hello World!'
                }
                }
            },
            {
                opcode: 'commentBoolean',
                blockType: BlockType.BOOLEAN,
                text: '// [COMMENT]',
                arguments: {
                COMMENT: {
                    type: ArgumentType.STRING,
                    defaultValue: 'true'
                }
                }
            },
            {
                opcode: 'commentReporter',
                blockType: BlockType.REPORTER,
                text: '// [COMMENT]',
                arguments: {
                COMMENT: {
                    type: ArgumentType.STRING,
                    defaultValue: 'goodbye!'
                }
                }
            },
            {
                opcode: 'commentHat',
                blockType: BlockType.HAT,
                text: '// [COMMENT]',
                arguments: {
                COMMENT: {
                    type: ArgumentType.STRING,
                    defaultValue: 'Hat Block'
                }
                }
            },
            {
                opcode: 'commentLoop',
                blockType: BlockType.LOOP,
                text: '// [COMMENT]',
                arguments: {
                COMMENT: {
                    type: ArgumentType.STRING,
                    defaultValue: 'Cap Block'
                }
                }
            }
            ]
        };
    }

    commentCommand (args) {
        // Do nothing
    }
    commentBoolean (args) {
        return '';
    }
    commentReporter (args) {
        return '';
    }
    commentHat (args) {
        return false;
    }
    commentLoop (args) {
        return false;
    }
}

module.exports = commentExt;